{
  "title": "Lower Class Science Exam",
   "description": "A comprehensive science exam for lower classes covering various topics",
   "timeLimit": 60,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "description": "Multiple Choice",
           "questions": [
               {
                   "text": "What is the largest planet in our solar system?",
                   "type": "multiple-choice",
                   "marks": 1,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Earth", "isCorrect": false, "letter": "A"},
                       {"text": "Saturn", "isCorrect": false, "letter": "B"},
                       {"text": "Jupiter", "isCorrect": true, "letter": "C"},
                       {"text": "Uranus", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "C",
                   "explanation": "Jupiter is the largest planet in terms of diameter and mass."
               },
               {
                   "text": "Which part of a plant makes food?",
                   "type": "multiple-choice",
                   "marks": 1,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Root", "isCorrect": false, "letter": "A"},
                       {"text": "Stem", "isCorrect": false, "letter": "B"},
                       {"text": "Leaf", "isCorrect": true, "letter": "C"},
                       {"text": "Flower", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "C",
                   "explanation": "Leaves are responsible for photosynthesis, which is how plants make their food."
               }
           ]
       },
       {
           "name": "B",
           "description": "Open Ended",
           "questions": [
               {
                   "text": "Describe the water cycle and its importance.",
                   "type": "open-ended",
                   "marks": 5,
                   "difficulty": "medium",
                   "correctAnswer": "The water cycle, also known as the hydrologic cycle, is the continuous process by which water is circulated between the Earth and the atmosphere. It involves the movement of water in three phases: liquid, solid (ice), and gas (water vapor). The water cycle is important because it helps regulate Earth's climate, provides water for plants and animals, and shapes our landscape through erosion and deposition.",
                   "gradingCriteria": [
                       {"criteria": "Description of the water cycle process", "points": 2},
                       {"criteria": "Importance of the water cycle", "points": 2},
                       {"criteria": "Clarity and coherence of the answer", "points": 1}
                   ]
               }
           ]
       },
       {
           "name": "C",
           "description": "True / False",
           "questions": [
               {
                   "text": "The sun is a star.",
                   "type": "true-false",
                   "marks": 1,
                   "difficulty": "easy",
                   "options": [
                       {"text": "True", "isCorrect": true, "letter": "A"},
                       {"text": "False", "isCorrect": false, "letter": "B"}
                   ],
                   "correctAnswer": "True",
                   "explanation": "The sun is indeed a star, specifically a G-type main-sequence star."
               }
           ]
       },
       {
           "name": "D",
           "description": "Short Answer",
           "questions": [
               {
                   "text": "What is the function of the mitochondria in a cell?",
                   "type": "short-answer",
                   "marks": 2,
                   "difficulty": "medium",
                   "correctAnswer": "The mitochondria are the powerhouses of the cell, responsible for generating most of the cell's supply of adenosine triphosphate (ATP), used as a source of chemical energy.",
                   "keyPoints": ["Mitochondria", "Powerhouse of the cell", "Energy production"],
                   "explanation": "Mitochondria are organelles found in the cells of most eukaryotes, including animals, plants, and fungi. They are often referred to as the 'powerhouses' of eukaryotic cells because they generate most of the cell's supply of adenosine triphosphate (ATP), which is used as a source of chemical energy."
               }
           ]
       },
       {
           "name": "E",
           "description": "Fill in Blank",
           "questions": [
               {
                   "text": "The process by which plants make their own food from sunlight is called ____________________.",
                   "type": "fill-in-blank",
                   "marks": 1,
                   "difficulty": "easy",
                   "correctAnswer": "photosynthesis",
                   "acceptableAnswers": ["photosynthesis", "photo synthesis"],
                   "explanation": "Photosynthesis is the process by which green plants, algae, and some bacteria convert light energy, usually from the sun, into chemical energy stored in glucose, a type of sugar."
               }
           ]
       },
       {
           "name": "F",
           "description": "Matching",
           "questions": [
               {
                   "text": "Match the following types of rocks with their descriptions.",
                   "type": "matching",
                   "marks": 3,
                   "difficulty": "medium",
                   "leftItems": ["Igneous", "Sedimentary", "Metamorphic"],
                   "rightItems": ["Formed from the cooling and solidification of magma or lava", "Formed from the accumulation and compression of sediments", "Formed from the alteration of existing rocks under high pressure and temperature"],
                   "correctAnswer": [
                       {"left": "Igneous", "right": "Formed from the cooling and solidification of magma or lava"},
                       {"left": "Sedimentary", "right": "Formed from the accumulation and compression of sediments"},
                       {"left": "Metamorphic", "right": "Formed from the alteration of existing rocks under high pressure and temperature"}
                   ],
                   "explanation": "Igneous rocks are formed from the cooling and solidification of magma or lava. Sedimentary rocks are formed from the accumulation and compression of sediments. Metamorphic rocks are formed from the alteration of existing rocks under high pressure and temperature."
               }
           ]
       },
       {
           "name": "G",
           "description": "Ordering",
           "questions": [
               {
                   "text": "Put the following stages of the water cycle in order.",
                   "type": "ordering",
                   "marks": 2,
                   "difficulty": "medium",
                   "items": ["Evaporation", "Condensation", "Precipitation", "Runoff"],
                   "correctAnswer": [0, 1, 2, 3],
                   "explanation": "The correct order is: Evaporation (water evaporates from the surface), Condensation (water vapor condenses into clouds), Precipitation (water falls back to the Earth as rain, snow, etc.), Runoff (water flows over the land or through streams and rivers)."
               }
           ]
       }
   ]
}
